<template>
  <v-container class="py-8">
    <div class="d-flex flex-column flex-md-row align-start align-md-center mb-6">
      <div class="flex-grow-1">
        <h1 class="text-h4 font-weight-bold mb-1">Services</h1>
        <div class="text-body-2 text--secondary">Book an appointment — pick a service and time slot.</div>
      </div>
    </div>

    <v-alert v-if="error" type="error" outlined class="rounded-lg mb-6">{{ error }}</v-alert>
    <v-alert
      v-else-if="!loading && salonEnabled === false"
      type="info"
      outlined
      class="rounded-lg mb-6"
    >
      This shop is configured as a <strong>normal store</strong> — bookings are disabled. Ask the merchant to switch to
      <strong>Salon</strong> under Admin → Store settings.
    </v-alert>
    <v-progress-circular v-else-if="loading" indeterminate color="primary" class="d-block mx-auto my-10" />

    <v-row v-else>
      <v-col v-for="s in services" :key="s.id" cols="12" md="6" lg="4">
        <v-card outlined class="rounded-xl">
          <v-img
            v-if="serviceCardImage(s)"
            :src="serviceCardImage(s)"
            :alt="s.name"
            height="160"
            cover
            class="rounded-t-xl"
          />
          <v-card-title class="pb-2">{{ s.name }}</v-card-title>
          <v-card-text class="pt-0">
            <div class="text-body-2 text--secondary mb-3" style="white-space: pre-wrap">{{ s.description }}</div>
            <div class="d-flex flex-wrap align-center">
              <v-chip small class="mr-2 mb-2" color="primary" text-color="white">
                {{ s.durationMinutes }} min
              </v-chip>
              <v-chip small class="mb-2" color="secondary" text-color="white">
                R {{ formatMoney(s.priceZar) }}
              </v-chip>
            </div>
          </v-card-text>
          <v-card-actions class="pt-0">
            <v-spacer />
            <v-btn color="primary" class="text-none font-weight-bold" :to="bookLink(s.id)">Book</v-btn>
          </v-card-actions>
        </v-card>
      </v-col>
      <v-col v-if="!services.length" cols="12">
        <v-alert type="info" outlined class="rounded-lg">No services available yet.</v-alert>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { fetchSalonServices } from '@/services/salonPublic'

export default {
  name: 'SalonServicesView',
  data() {
    return { loading: true, error: '', salonEnabled: true, services: [] }
  },
  async created() {
    try {
      const slug = String(this.$route.params.merchantSlug || '').trim()
      const res = await fetchSalonServices(slug)
      this.salonEnabled = Boolean(res && res.salonEnabled)
      this.services = (res && res.services) || []
    } catch (e) {
      this.error = e && e.message ? e.message : 'Could not load services.'
    } finally {
      this.loading = false
    }
  },
  methods: {
    serviceCardImage(s) {
      const u = s && s.imageUrl != null ? String(s.imageUrl).trim() : ''
      return u || ''
    },
    formatMoney(v) {
      const n = Number(v)
      if (!Number.isFinite(n)) return String(v || '')
      return n.toFixed(2)
    },
    bookLink(serviceId) {
      const slug = encodeURIComponent(String(this.$route.params.merchantSlug || ''))
      return `/m/${slug}/salon/book/${encodeURIComponent(serviceId)}`
    }
  }
}
</script>

